// Format Filevine data into Clio-compatible billing records
const items = $input.first().json;
const matters = items.matters || items.data || [];

const billingRecords = matters.map(m => {
  // Strip null/empty values
  const clean = (obj) => Object.fromEntries(
    Object.entries(obj).filter(([_, v]) => v != null && v !== '')
  );

  return clean({
    matter_id: m.matter_id,
    client_name: m.client,
    case_type: m.type,
    hours: m.unbilled_hours,
    rate: m.unbilled_amount / m.unbilled_hours,
    total: m.unbilled_amount,
    last_activity: m.last_activity,
    attorney: m.attorney,
    description: `Time entries for ${m.matter_id} — ${m.type}`,
    sync_date: new Date().toISOString().split('T')[0]
  });
});

// Check for potential conflicts (duplicate matter_ids, zero amounts)
const conflicts = billingRecords.filter(r => !r.hours || r.hours <= 0 || !r.matter_id);
const valid = billingRecords.filter(r => r.hours > 0 && r.matter_id);

return [{
  json: {
    valid_records: valid,
    conflicts: conflicts,
    has_conflicts: conflicts.length > 0,
    total_records: billingRecords.length,
    total_amount: valid.reduce((sum, r) => sum + (r.total || 0), 0),
    sync_date: new Date().toISOString().split('T')[0],
    firm: 'Greenfield & Associates'
  }
}];
